import{_ as e,c as r,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"ユーザー利用規約: サービスルール | OpenCodeDocs","description":"OpenCodeDocsのユーザー利用規約について、サービス利用ルール、知的財産権の帰属、免責事項を理解し、双方の権利と義務を明確にします。","frontmatter":{"title":"ユーザー利用規約: サービスルール | OpenCodeDocs","sidebarTitle":"5分でルールを理解","subtitle":"ユーザー利用規約: サービスルール","description":"OpenCodeDocsのユーザー利用規約について、サービス利用ルール、知的財産権の帰属、免責事項を理解し、双方の権利と義務を明確にします。"},"headers":[],"relativePath":"ja/terms.md","filePath":"ja/terms.md"}'),i={name:"ja/terms.md"};function o(n,a,s,h,d,c){return l(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="ユーザーサービス利用規約" tabindex="-1">ユーザーサービス利用規約 <a class="header-anchor" href="#ユーザーサービス利用規約" aria-label="Permalink to &quot;ユーザーサービス利用規約&quot;">​</a></h1><p>最終更新日：2026-01-01<br> 発効日：2026-01-01</p><p>OpenCodeDocsへようこそ！当社のサービスをご利用いただく前に、本ユーザーサービス利用規約（以下「本規約」）を慎重にお読みください。当社のサービスをご利用いただくことで、本規約に同意したものとみなされます。</p><h2 id="_1-サービス説明" tabindex="-1">1. サービス説明 <a class="header-anchor" href="#_1-サービス説明" aria-label="Permalink to &quot;1. サービス説明&quot;">​</a></h2><p>OpenCodeDocsは、AIツールのチュートリアルに特化したオープンプラットフォームであり、以下のサービスを提供します：</p><ul><li><strong>チュートリアルコンテンツ</strong>：オープンソースAIツール（Claude Code、Cursor、LangChainなど）の使用チュートリアル</li><li><strong>コード検証</strong>：ソースコードリポジトリに基づき、チュートリアル内のコードの実行可能性を自動検証</li><li><strong>コミュニティ機能</strong>：ユーザーはGitHubを通じてコンテンツへの貢献や議論に参加可能</li></ul><p>当社は、事前の通知なしに、サービスの一部または全部を変更、一時停止、または終了する権利を留保します。</p><h2 id="_2-アカウント登録と管理" tabindex="-1">2. アカウント登録と管理 <a class="header-anchor" href="#_2-アカウント登録と管理" aria-label="Permalink to &quot;2. アカウント登録と管理&quot;">​</a></h2><h3 id="登録条件" tabindex="-1">登録条件 <a class="header-anchor" href="#登録条件" aria-label="Permalink to &quot;登録条件&quot;">​</a></h3><ul><li>お客様は16歳以上（または居住地の法定年齢に達していること）である必要があります</li><li>真実かつ正確な登録情報を提供してください</li><li>ユーザー1人につき1つのアカウントのみ登録可能です</li></ul><h3 id="アカウントセキュリティ" tabindex="-1">アカウントセキュリティ <a class="header-anchor" href="#アカウントセキュリティ" aria-label="Permalink to &quot;アカウントセキュリティ&quot;">​</a></h3><ul><li>アカウント情報はお客様の責任で管理し、他者と共有しないでください</li><li>アカウントの不正利用が発覚した場合、直ちに当社までご連絡ください</li><li>アカウント管理不適切により生じた損害は、お客様が負担します</li></ul><h3 id="アカウント削除" tabindex="-1">アカウント削除 <a class="header-anchor" href="#アカウント削除" aria-label="Permalink to &quot;アカウント削除&quot;">​</a></h3><p>いつでもアカウント削除の申請が可能です。削除後、お客様の個人データは30日以内に削除されますが、公開されたコンテンツは引き続き残存する場合があります。</p><h2 id="_3-ユーザー行動規範" tabindex="-1">3. ユーザー行動規範 <a class="header-anchor" href="#_3-ユーザー行動規範" aria-label="Permalink to &quot;3. ユーザー行動規範&quot;">​</a></h2><p>本プラットフォームをご利用の際、お客様は以下の行為を行わないことに同意します：</p><ul><li>違法、有害、脅威、嫌がらせ、中傷、または権利侵害を含むコンテンツの投稿</li><li>他人になりすましたり、虚偽の申告を行うこと</li><li>許可なく他人のアカウントまたはシステムへのアクセス</li><li>サービスの正常な運営を妨害または破壊する行為</li><li>自動化ツールを使用して大規模なコンテンツ収集を行うこと（適切なAPI使用を除く）</li><li>ライセンス契約に従わずにチュートリアルコンテンツを商用目的で使用すること</li></ul><h2 id="_4-知的財産権" tabindex="-1">4. 知的財産権 <a class="header-anchor" href="#_4-知的財産権" aria-label="Permalink to &quot;4. 知的財産権&quot;">​</a></h2><h3 id="オープンソースライセンスについて" tabindex="-1">オープンソースライセンスについて <a class="header-anchor" href="#オープンソースライセンスについて" aria-label="Permalink to &quot;オープンソースライセンスについて&quot;">​</a></h3><ul><li><strong>チュートリアルコンテンツ</strong>：<a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a> ライセンスを採用。非商業的な共有と改変を許可しますが、帰名表示と同一条件での共有が必要です</li><li><strong>ウェブサイト構築</strong>：本プロジェクトは<a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a>に基づいて構築されており、MITライセンスに準拠します</li><li><strong>ユーザー貢献</strong>：お客様が提出したコンテンツは、上記ライセンスを遵守することを条件に、プラットフォームでの使用を許諾するものとします</li></ul><p>OpenCodeDocsの商標、ロゴ、およびその他のブランド識別子は法的に保護されており、許可なく使用することはできません。</p><h2 id="_5-免責事項" tabindex="-1">5. 免責事項 <a class="header-anchor" href="#_5-免責事項" aria-label="Permalink to &quot;5. 免責事項&quot;">​</a></h2><ul><li><strong>サービス中断</strong>：当社はサービスの中断やエラーを保証しません。メンテナンス、アップグレード、または不可抗力によるサービス中断について、当社は責任を負いません</li><li><strong>コンテンツの正確性</strong>：チュートリアルコンテンツは参考情報であり、あらゆる環境での可用性を保証しません</li><li><strong>コード使用のリスク</strong>：チュートリアル内のコードを実行する際は、お客様自身の責任で行う必要があります。隔離環境でのテストを推奨します</li><li><strong>第三者リンク</strong>：本サイトには第三者のウェブサイトへのリンクが含まれる場合がありますが、そのコンテンツについて責任を負いません</li></ul><h2 id="_6-規約の変更" tabindex="-1">6. 規約の変更 <a class="header-anchor" href="#_6-規約の変更" aria-label="Permalink to &quot;6. 規約の変更&quot;">​</a></h2><p>当社は、本規約を随時変更する場合があります。変更後の規約はウェブサイト上で公開され、以下の方法でお客様に通知されます：</p><ul><li>ウェブサイトの目立つ場所での公告</li><li>登録メールアドレスへの通知送信（該当する場合）</li></ul><p>当社のサービスを継続してご利用いただくことで、お客様は変更後の規約に同意したものとみなされます。変更に同意されない場合は、サービスのご利用を中止してください。</p><h2 id="_7-紛争解決" tabindex="-1">7. 紛争解決 <a class="header-anchor" href="#_7-紛争解決" aria-label="Permalink to &quot;7. 紛争解決&quot;">​</a></h2><ul><li><strong>準拠法</strong>：本規約は中華人民共和国の法に準拠します</li><li><strong>紛争解決</strong>：双方は友好的な協議を通じて紛争を解決する必要があります。協議が不調に終わった場合、いずれか一方は被告の所在地の管轄権を有する人民法院に訴訟を提起することができます</li></ul><h2 id="_8-お問い合わせ" tabindex="-1">8. お問い合わせ <a class="header-anchor" href="#_8-お問い合わせ" aria-label="Permalink to &quot;8. お問い合わせ&quot;">​</a></h2><p>本規約に関するご質問がある場合は、以下までご連絡ください：</p><ul><li><strong>メール</strong>：<a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>GitHub</strong>：<a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">vbgate/opencodedocs</a></li></ul>',32)])])}const g=e(i,[["render",o]]);export{p as __pageData,g as default};
